// The debounce function delays the execution of a function until after a certain amount of time has passed since its last call.
function debounce(func, delay) {
  let timeoutId;
  return function(...args) {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => {
      func.apply(this, args);
    }, delay);
  };
}

// Example usage:
function onInputChange(value) {
  console.log('Input changed:', value);
}

const debouncedInputChange = debounce(onInputChange, 300); // 300ms delay

// Simulate multiple rapid input changes:
debouncedInputChange('a');
debouncedInputChange('ab');
debouncedInputChange('abc'); // Only this call will actually trigger onInputChange after 300ms
```
